import React, { useState } from 'react';
import { ImagePlus, Calendar, Users, Package, Tag, DollarSign } from 'lucide-react';

const FormularioOferta = ({ onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    producto: '', 
    precioViejo: '', 
    precioNuevo: '', 
    peso: '', 
    stock: '', 
    imagen: '',
    fechaVencimiento: '', // NUEVO
    limitePorCliente: '3'  // NUEVO
  });

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({ ...formData, imagen: reader.result });
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    
    // Validación de seguridad para que sea una oferta real
    if (Number(formData.precioNuevo) >= Number(formData.precioViejo)) {
      alert("El precio de oferta debe ser menor al precio normal.");
      return;
    }

    onSave({ 
      ...formData, 
      id: Date.now(),
      precioViejo: Number(formData.precioViejo),
      precioNuevo: Number(formData.precioNuevo),
      peso: parseFloat(formData.peso),
      stock: parseInt(formData.stock),
      limitePorCliente: parseInt(formData.limitePorCliente),
      fechaVencimiento: formData.fechaVencimiento // Se envía la fecha elegida
    });
  };

  return (
    <div style={formCard}>
      <h3 style={{marginTop: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '10px'}}>
        <Tag color="#e67e22" size={20}/> Publicar Oferta Profesional
      </h3>
      
      <form onSubmit={handleSubmit}>
        {/* Selector de Imagen */}
        <div style={imageUploadContainer}>
          {formData.imagen ? (
            <img src={formData.imagen} alt="Preview" style={previewImage} />
          ) : (
            <label style={uploadLabel}>
              <ImagePlus size={30} />
              <span>Subir Foto del Producto</span>
              <input type="file" accept="image/*" onChange={handleImageChange} style={{display: 'none'}} />
            </label>
          )}
        </div>

        <div style={inputGroup}>
          <label style={miniLabel}>Nombre del Producto</label>
          <input placeholder="Ej: Fernet Branca 750ml" style={inputStyle} required 
            onChange={e => setFormData({...formData, producto: e.target.value})} />
        </div>
        
        <div style={{ display: 'flex', gap: '10px' }}>
          <div style={{flex: 1}}>
            <label style={miniLabel}>Precio Normal ($)</label>
            <input type="number" placeholder="1800" style={inputStyle} required 
              onChange={e => setFormData({...formData, precioViejo: e.target.value})} />
          </div>
          <div style={{flex: 1}}>
            <label style={{...miniLabel, color: '#e67e22'}}>Precio Oferta ($)</label>
            <input type="number" placeholder="1200" style={{...inputStyle, borderColor: '#e67e22'}} required 
              onChange={e => setFormData({...formData, precioNuevo: e.target.value})} />
          </div>
        </div>

        <div style={rowStyle}>
          <div style={{ flex: 1 }}>
            <label style={miniLabel}><Package size={12}/> Stock</label>
            <input type="number" placeholder="Cant." style={inputStyle} required 
              onChange={e => setFormData({...formData, stock: e.target.value})} />
          </div>
          <div style={{ flex: 1 }}>
            <label style={miniLabel}><Users size={12}/> Límite/Persona</label>
            <input type="number" value={formData.limitePorCliente} style={inputStyle} required 
              onChange={e => setFormData({...formData, limitePorCliente: e.target.value})} />
          </div>
          <div style={{ flex: 1 }}>
            <label style={miniLabel}>Peso (kg)</label>
            <input type="number" step="0.001" placeholder="0.500" style={inputStyle} required 
              onChange={e => setFormData({...formData, peso: e.target.value})} />
          </div>
        </div>

        {/* NUEVO: CAMPO DE VENCIMIENTO */}
        <div style={{marginBottom: '15px'}}>
          <label style={miniLabel}><Calendar size={12}/> ¿Cuándo termina esta oferta?</label>
          <input 
            type="datetime-local" 
            style={inputStyle} 
            required 
            onChange={e => setFormData({...formData, fechaVencimiento: e.target.value})} 
          />
          <small style={{color: '#94a3b8', fontSize: '0.7rem'}}>Pasado este tiempo, la oferta desaparecerá.</small>
        </div>

        <div style={{ display: 'flex', gap: '10px' }}>
          <button type="submit" style={btnSave}>Publicar Ahora</button>
          <button type="button" onClick={onCancel} style={btnCancel}>Cancelar</button>
        </div>
      </form>
    </div>
  );
};

// --- ESTILOS (Manteniendo tus constantes) ---
const imageUploadContainer = { width: '100%', height: '140px', background: '#f1f5f9', borderRadius: '12px', marginBottom: '15px', overflow: 'hidden', border: '2px dashed #cbd5e1' };
const uploadLabel = { width: '100%', height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: '#64748b', gap: '10px' };
const previewImage = { width: '100%', height: '100%', objectFit: 'cover' };
const formCard = { background: 'white', padding: '25px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)' };
const inputGroup = { marginBottom: '10px' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #e2e8f0', boxSizing: 'border-box', fontSize: '0.9rem' };
const rowStyle = { display: 'flex', gap: '10px', marginBottom: '10px', background: '#f8fafc', padding: '10px', borderRadius: '10px' };
const miniLabel = { fontSize: '0.7rem', color: '#94a3b8', display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '4px', fontWeight: 'bold' };
const btnSave = { flex: 1, padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const btnCancel = { flex: 1, padding: '12px', background: '#f1f5f9', color: '#64748b', border: 'none', borderRadius: '10px', cursor: 'pointer' };

export default FormularioOferta;
